(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["profile"],{"60be":function(n,e,a){"use strict";a.r(e);var r=function(){var n=this,e=n.$createElement,a=n._self._c||e;return a("v-container",{staticStyle:{"max-width":"960px"}},[a("section",{staticClass:"markdown",domProps:{innerHTML:n._s(n.markdown)}})])},t=[],i='\x3c!-- # @MadakaHeri --\x3e\n# マダカヘリ\n\n<a class="v-btn theme--dark v-size--x-small grey darken-2" href="https://madakaheri.github.io" target="_brank">公式サイト</a>\n<a class="v-btn theme--dark v-size--x-small grey darken-2" href="https://github.com/MadakaHeri" target="_brank">GitHub</a>\n<a class="v-btn theme--dark v-size--x-small grey darken-2" href="https://twitter.com/MadakaHeri" target="_brank">Twitter</a>\n<a class="v-btn theme--dark v-size--x-small grey darken-2" href="https://marshmallow-qa.com/madakaheri" target="_brank">マシュマロ</a>\n<a class="v-btn theme--dark v-size--x-small grey darken-2" href="https://qiita.com/MadakaHeri" target="_brank">Qiita</a>\n<a class="v-btn theme--dark v-size--x-small grey darken-2" href="https://www.youtube.com/channel/UCdYdqeVNy9D1ZDWrE6Z6uMA" target="_brank">YouTube</a>\n\n```\n🆕 2021.03.15 - 現在、大阪で新たな職場を探しています！\n```\n<br>\n性別：男 / 出身：大阪府 / 血液型：O型<br>\n大学卒業後に上京。28歳までDTMで主に小劇団の劇伴を請負いながら音楽活動をし、以降ランサーズでWeb系フリーランスを少々。 33歳から元ランサーズのお客様の会社に就職。現在に至る。<br>\n<br>\n\n## 📣 ごあいさつ\n\n東京のとあるITスタートアップでフルスタックエンジニア兼開発リーダーをやっています！  \n主にレビューや価格分析の分野でVue.jsでのアプリ開発からMySQLとLaravelまたはAWSでサーバーレスでバックエンド設計・開発をしています。  \n最近はAWS Amplify（Firebase的なもの）で組むのが簡単で工数少なく開発出来て楽ですね。  \nAmplify未対応の部分はSAMで開発します。  \n\nサーバーレスのややこしい部分はハマるととんでもない労力を割くことになるので、出来るだけ基本に忠実に、無理せずシンプルな構成を心がけています。  \nチームメンバーがメンテできないシステムなんて負の遺産にしかならないですからね、、\n\n\n\x3c!-- ## 👀プロフィール --\x3e\n\n\x3c!-- 性別：男 / 出身：大阪府 / 血液型：O型\n\n大学時代から28歳まで、プロとして音楽で生きる事だけを見て生きていました。  \n単身東京に出るも、今のようにランサーズなど便利な案件募集サイトが無く、怪しい掲示板などで主に舞台の劇伴制作を受けながらバイトに励む日々。周囲が次々にドロップアウトしていく中、色んなバイトをして食い繋いでいました、、  \n主にやっていたのは建材や自動車の塗装工（期間工含む）、楽しかったのはビデオカメラマンです！  \n\nその後、WordPress全盛期あたりから密かに勉強を始めていた（スクールにも通ってた）WEB制作の勉強をしてランサーズデビューを果たしました。フリーランスは夢が広がって楽しかったなぁ、、  \n現在の職場はランサーズ時代のお客様に引き取って貰うカタチで社員になりました。  \n\n馬鹿みたいな生き方した割にはマシな人生に落ち着いたんじゃないかなぁと、密かに思っています。  \n今後の夢は、、VTuberなりたい！（笑） --\x3e\n\x3c!-- 性別：男 / 出身：大阪府 / 血液型：O型  \n大学卒業後に上京。28歳までDTMで主に小劇団の劇伴を請負いながら音楽活動をし、以降ランサーズでWeb系フリーランスを少々。 33歳から元ランサーズのお客様の会社に就職。現在に至る。 --\x3e\n\n<br>\n\n## 🌱 スキル\n\n### 🧑🏻‍💻 使用マシン\n- MacBookPro\n\n### 🖥 WEB系\n- HTML / CSS\n- SCSS\n- JavaScript（ES6）\n- PHP7\n- jQuery\n- Vue.js\n- node.js\n- Laravel\n\n### 🦄 AWS（主に使用したもの）\n- SAM / Amplify\n- EC2 / Lambda / StepFunctions\n- Aurora / Dynamo DB / S3\n- SQS / Kinesis\n- SNS /  SES\n- CodePipeline / CodeBuild / CodeDeploy\n\n### 🎨 デザイン\n＊ Adobe系は常駐するし謎フォルダ勝手に作るので捨てました。\n- Affinity Designer\n- Affinity Photo\n- Sketch\n- Fusion 360（ほぼ趣味）\n- カラーコーディネーター３級\n\n\x3c!---\nMadakaHeri/MadakaHeri is a ✨ special ✨ repository because its `README.md` (this file) appears on your GitHub profile.\nYou can click the Preview link to take a look at your changes.\n---\x3e\n',s=a("0e54"),o=a.n(s),l={computed:{markdown:function(){return o()(i)}}},c=l,d=a("2877"),k=a("6544"),b=a.n(k),m=a("a523"),u=Object(d["a"])(c,r,t,!1,null,null,null);e["default"]=u.exports;b()(u,{VContainer:m["a"]})}}]);
